function compilePolyline(points){let total=0;const segments=[];for(let i=0;i<points.length-1;i++){const [ax,az]=points[i],[bx,bz]=points[i+1],dx=bx-ax,dz=bz-az,length=Math.hypot(dx,dz);segments.push({ax,az,dx,dz,length,lengthSq:length*length,startLength:total});total+=length}return {segments,totalLength:total}}
